from collections import deque, defaultdict
def find_min_height_trees(n, edges):
    if n == 1:
        return [0]
    g = defaultdict(list)
    deg = [0] * n
    for u, v in edges:
        g[u].append(v); g[v].append(u)
        deg[u] += 1; deg[v] += 1
    q = deque([i for i in range(n) if deg[i] == 1])
    remain = n
    while remain > 2:
        size = len(q)
        remain -= size
        for _ in range(size):
            u = q.popleft()
            for v in g[u]:
                deg[v] -= 1
                if deg[v] == 1:
                    q.append(v)
    return list(q)

